1	//! `Separator` component machine and connect API.
2	//!
3	//! `Separator` is a stateless attribute mapper that renders a horizontal or
4	//! vertical dividing line. It has no state machine — the framework-agnostic
5	//! core consists solely of `Props`, `Part`, and `Api`, which produces the
6	//! appropriate ARIA role and orientation attributes for the root element.
7	//!
8	//! See `spec/components/utility/separator.md` for the authoritative contract.
9	
10	use alloc::string::String;
11	
12	use ars_core::{AriaAttr, AttrMap, ComponentPart, ConnectApi, HasId, HtmlAttr};
13	use ars_i18n::Orientation;
14	
15	/// Props for the `Separator` component.
16	#[derive(Clone, Debug, Default, PartialEq, HasId)]
17	pub struct Props {
18	    /// Component instance ID.
19	    pub id: String,
20	
21	    /// The orientation of the separator. Defaults to `Orientation::Horizontal`
22	    /// via `Orientation`'s own `Default` impl.
23	    pub orientation: Orientation,
24	
25	    /// Whether the separator is purely decorative and hidden from the
26	    /// accessibility tree.
27	    pub decorative: bool,
28	}
29	
30	impl Props {
31	    /// Returns fresh [`Props`] with the documented defaults — equivalent
32	    /// to [`Default::default`], offered as the entry point for the
33	    /// builder chain.
34	    #[must_use]
35	    pub fn new() -> Self {
36	        Self::default()
37	    }
38	
39	    /// Sets the component instance ID.
40	    #[must_use]
41	    pub fn id(mut self, id: impl Into<String>) -> Self {
42	        self.id = id.into();
43	        self
44	    }
45	
46	    /// Sets the layout orientation of the separator.
47	    #[must_use]
48	    pub const fn orientation(mut self, value: Orientation) -> Self {
49	        self.orientation = value;
50	        self
51	    }
52	
53	    /// Sets whether the separator is purely decorative (hidden from the
54	    /// accessibility tree).
55	    #[must_use]
56	    pub const fn decorative(mut self, value: bool) -> Self {
57	        self.decorative = value;
58	        self
59	    }
60	}
61	
62	/// DOM parts of the `Separator` component.
63	#[derive(ComponentPart)]
64	#[scope = "separator"]
65	pub enum Part {
66	    /// The root element. See spec §2.1 for adapter element-type selection
67	    /// (`<hr>` for content separators, `<div>` for menu/toolbar/listbox).
68	    Root,
69	}
70	
71	/// The API for the `Separator` component.
72	///
73	/// Constructed via [`Api::new`] from [`Props`] and queried via
74	/// [`Api::root_attrs`] or the [`ConnectApi`] dispatch.
75	#[derive(Clone, Debug)]
76	pub struct Api {
77	    props: Props,
78	}
79	
80	impl Api {
81	    /// Creates a new `Api` instance from the given props.
82	    #[must_use]
83	    pub const fn new(props: Props) -> Self {
84	        Self { props }
85	    }
86	
87	    /// Returns a reference to the underlying [`Props`].
88	    ///
89	    /// Adapters typically read individual fields through the dedicated
90	    /// accessors (`id`, `orientation`, `decorative`); this method is the
91	    /// escape hatch for when the full struct is needed (e.g., to clone it
92	    /// into a fresh [`Api`] for a re-render).
93	    #[must_use]
94	    pub const fn props(&self) -> &Props {
95	        &self.props
96	    }
97	
98	    /// Returns the component's instance ID.
99	    #[must_use]
100	    pub fn id(&self) -> &str {
101	        &self.props.id
102	    }
103	
104	    /// Returns the layout orientation of the separator.
105	    #[must_use]
106	    pub const fn orientation(&self) -> Orientation {
107	        self.props.orientation
108	    }
109	
110	    /// Returns whether the separator is purely decorative.
111	    #[must_use]
112	    pub const fn decorative(&self) -> bool {
113	        self.props.decorative
114	    }
115	
116	    /// Returns the attributes for the root element.
117	    ///
118	    /// Semantic separators get `role="separator"` plus `aria-orientation`
119	    /// matching the layout axis, and `data-ars-orientation` for styling.
120	    /// Decorative separators get `role="none"` (the modern WAI-ARIA 1.2
121	    /// preferred form, synonymous with `role="presentation"`); they omit
122	    /// `aria-orientation` and the `data-ars-orientation` styling hook,
123	    /// because a decorative separator is invisible to assistive technology
124	    /// and component-managed orientation styling is not applied.
125	    #[must_use]
126	    pub fn root_attrs(&self) -> AttrMap {
127	        let mut attrs = AttrMap::new();
128	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::Root.data_attrs();
129	
130	        attrs.set(scope_attr, scope_val).set(part_attr, part_val);
131	
132	        if self.props.decorative {
133	            // Decorative separators are removed from the accessibility tree
134	            // via `role="none"`. No `aria-hidden` (redundant for an element
135	            // with no children) and no `data-ars-orientation` (decorative
136	            // separators do not participate in component orientation styling).
137	            attrs.set(HtmlAttr::Role, "none");
138	        } else {
139	            let orientation_str = match self.props.orientation {
140	                Orientation::Horizontal => "horizontal",
141	                Orientation::Vertical => "vertical",
142	            };
143	
144	            attrs
145	                .set(HtmlAttr::Data("ars-orientation"), orientation_str)
146	                .set(HtmlAttr::Role, "separator")
147	                .set(HtmlAttr::Aria(AriaAttr::Orientation), orientation_str);
148	        }
149	
150	        attrs
151	    }
152	}
153	
154	impl ConnectApi for Api {
155	    type Part = Part;
156	
157	    fn part_attrs(&self, part: Part) -> AttrMap {
158	        match part {
159	            Part::Root => self.root_attrs(),
160	        }
161	    }
162	}
163	
164	#[cfg(test)]
165	mod tests {
166	    use ars_core::HasId;
167	    use insta::assert_snapshot;
168	
169	    use super::*;
170	
171	    fn snapshot_attrs(attrs: &AttrMap) -> String {
172	        format!("{attrs:#?}")
173	    }
174	
175	    fn horizontal() -> Props {
176	        Props::default()
177	    }
178	
179	    fn vertical() -> Props {
180	        Props {
181	            orientation: Orientation::Vertical,
182	            ..Props::default()
183	        }
184	    }
185	
186	    fn decorative_horizontal() -> Props {
187	        Props {
188	            decorative: true,
189	            ..Props::default()
190	        }
191	    }
192	
