1	//! `Group` component connect API.
2	//!
3	//! `Group` is a stateless semantic grouping wrapper. The framework-agnostic
4	//! core consists of [`Props`], the [`GroupRole`] role selector, the [`Part`]
5	//! taxonomy, [`Api`], and a [`GroupContext`] struct that adapters publish so
6	//! descendant components can inherit `disabled`, `invalid`, and `read_only`
7	//! state without re-implementing the propagation themselves.
8	//!
9	//! Unlike [`Fieldset`](super::fieldset), which renders the native
10	//! `<fieldset>`/`<legend>` pair and is form-specific, `Group` is a lightweight
11	//! attribute mapper for any related set of controls (a cluster of buttons
12	//! sharing a disabled state, the input + steppers inside a NumberField, etc.).
13	//!
14	//! See `spec/components/utility/group.md` for the authoritative contract.
15	
16	use alloc::string::String;
17	
18	use ars_core::{AriaAttr, AttrMap, ComponentPart, ConnectApi, HasId, HtmlAttr};
19	use ars_i18n::Direction;
20	
21	/// The ARIA role applied to the [`Group`](self) container.
22	///
23	/// Defaults to [`GroupRole::Group`], a generic grouping role suitable for
24	/// related controls. Switch to [`GroupRole::Region`] when the group is a
25	/// landmark that should appear in a page summary (an accessible name is then
26	/// required by WAI-ARIA), or to [`GroupRole::Presentation`] to render the
27	/// container without any grouping semantics while still propagating state via
28	/// [`GroupContext`].
29	#[derive(Clone, Copy, Debug, PartialEq, Eq, Default)]
30	pub enum GroupRole {
31	    /// `role="group"` — a set of related UI elements not important enough to
32	    /// be included in a page summary or table of contents.
33	    #[default]
34	    Group,
35	    /// `role="region"` — a landmark region that is significant enough to be
36	    /// listed in a page summary. Requires an accessible name.
37	    Region,
38	    /// `role="presentation"` — removes the grouping semantics. Children are
39	    /// still grouped visually but not semantically.
40	    Presentation,
41	}
42	
43	/// Props for the [`Group`](self) component.
44	#[derive(Clone, Debug, Default, PartialEq, HasId)]
45	pub struct Props {
46	    /// Component instance ID. Always emitted on the root element so adapters
47	    /// and consumers can reference the container from other attributes
48	    /// (`aria-controls`, `aria-describedby`, etc.).
49	    pub id: String,
50	
51	    /// Whether the group and all contained controls are disabled. Propagated
52	    /// to descendants via [`GroupContext`] and surfaced on the root as
53	    /// `aria-disabled="true"` plus `data-ars-disabled` for styling.
54	    pub disabled: bool,
55	
56	    /// Whether the group is in an invalid state. Propagated to descendants
57	    /// via [`GroupContext`] and surfaced on the root as `aria-invalid="true"`
58	    /// plus `data-ars-invalid` for styling.
59	    pub invalid: bool,
60	
61	    /// Whether the group is read-only. Propagated to descendants via
62	    /// [`GroupContext`] and surfaced on the root as `aria-readonly="true"`
63	    /// plus `data-ars-readonly` for styling.
64	    pub read_only: bool,
65	
66	    /// The ARIA role for the group container. Defaults to [`GroupRole::Group`].
67	    pub role: GroupRole,
68	
69	    /// Layout direction for RTL support. When `Some(_)`, the resolved value
70	    /// is forwarded to the root element's `dir` attribute. When `None`, the
71	    /// element inherits direction from the DOM cascade.
72	    pub dir: Option<Direction>,
73	}
74	
75	impl Props {
76	    /// Returns fresh [`Props`] with the documented defaults — equivalent to
77	    /// [`Default::default`], offered as the entry point for the builder chain.
78	    #[must_use]
79	    pub fn new() -> Self {
80	        Self::default()
81	    }
82	
83	    /// Sets the component instance ID.
84	    #[must_use]
85	    pub fn id(mut self, id: impl Into<String>) -> Self {
86	        self.id = id.into();
87	        self
88	    }
89	
90	    /// Sets whether the group is disabled. Disabled state propagates to
91	    /// descendants through [`GroupContext`].
92	    #[must_use]
93	    pub const fn disabled(mut self, value: bool) -> Self {
94	        self.disabled = value;
95	        self
96	    }
97	
98	    /// Sets whether the group is invalid. Invalid state propagates to
99	    /// descendants through [`GroupContext`].
100	    #[must_use]
101	    pub const fn invalid(mut self, value: bool) -> Self {
102	        self.invalid = value;
103	        self
104	    }
105	
106	    /// Sets whether the group is read-only. Read-only state propagates to
107	    /// descendants through [`GroupContext`].
108	    #[must_use]
109	    pub const fn read_only(mut self, value: bool) -> Self {
110	        self.read_only = value;
111	        self
112	    }
113	
114	    /// Sets the ARIA role of the group container.
115	    #[must_use]
116	    pub const fn role(mut self, value: GroupRole) -> Self {
117	        self.role = value;
118	        self
119	    }
120	
121	    /// Sets the layout direction. Pass `Some(direction)` to forward an
122	    /// explicit `dir` attribute, or `None` to inherit from the DOM cascade.
123	    #[must_use]
124	    pub const fn dir(mut self, value: Option<Direction>) -> Self {
125	        self.dir = value;
126	        self
127	    }
128	}
129	
130	/// Context published by [`Group`](self) so descendant components can inherit
131	/// `disabled`, `invalid`, and `read_only` state without re-implementing the
132	/// propagation themselves.
133	///
134	/// Adapters MUST provide this value through their framework's context system
135	/// (`provide_context` in Leptos, `use_context_provider` in Dioxus). Descendant
136	/// components that participate in inheritance should merge each field with
137	/// their own props using a logical OR — a component is disabled if either it
138	/// or its containing group is disabled.
139	#[derive(Clone, Debug, Default, PartialEq, Eq)]
140	pub struct GroupContext {
141	    /// Whether the containing group is disabled.
142	    pub disabled: bool,
143	    /// Whether the containing group is in an invalid state.
144	    pub invalid: bool,
145	    /// Whether the containing group is read-only.
146	    pub read_only: bool,
147	}
148	
149	/// DOM parts of the [`Group`](self) component.
150	#[derive(ComponentPart)]
151	#[scope = "group"]
152	pub enum Part {
153	    /// The root container element. Renders as a `<div>` carrying the role,
154	    /// state attributes, and propagation context.
155	    Root,
156	}
157	
158	/// The API for the [`Group`](self) component.
159	///
160	/// Constructed via [`Api::new`] from [`Props`] and queried via
161	/// [`Api::root_attrs`], [`Api::group_context`], or the [`ConnectApi`] dispatch.
162	#[derive(Clone, Debug)]
163	pub struct Api {
164	    props: Props,
165	}
166	
167	impl Api {
168	    /// Creates a new `Api` instance from the given props.
169	    #[must_use]
170	    pub const fn new(props: Props) -> Self {
171	        Self { props }
172	    }
173	
174	    /// Returns a reference to the underlying [`Props`].
175	    #[must_use]
176	    pub const fn props(&self) -> &Props {
177	        &self.props
178	    }
179	
180	    /// Returns the component's instance ID.
181	    #[must_use]
182	    pub fn id(&self) -> &str {
183	        &self.props.id
184	    }
185	
186	    /// Returns the [`GroupContext`] that adapters should publish to
187	    /// descendants so they can inherit the group's disabled / invalid /
188	    /// read-only state.
189	    #[must_use]
190	    pub const fn group_context(&self) -> GroupContext {
191	        GroupContext {
192	            disabled: self.props.disabled,
193	            invalid: self.props.invalid,
194	            read_only: self.props.read_only,
195	        }
196	    }
197	
198	    /// Returns the attributes for the root element.
199	    ///
200	    /// Always emits the instance `id`, the scope/part data attributes, and a
201	    /// `role` derived from [`Props::role`]. State attributes
202	    /// (`aria-disabled`, `aria-invalid`, `aria-readonly` plus their
203	    /// `data-ars-*` styling counterparts) are emitted whenever the
204	    /// corresponding prop is `true`, regardless of the role — WAI-ARIA 1.2
205	    /// §5.4 preserves global states on `role="presentation"`, and React Aria
206	    /// follows the same convention. When [`Props::dir`] is `Some`, the
207	    /// resolved direction is forwarded to the `dir` attribute.
208	    #[must_use]
209	    pub fn root_attrs(&self) -> AttrMap {
210	        let mut attrs = AttrMap::new();
211	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::Root.data_attrs();
212	
213	        attrs
214	            .set(HtmlAttr::Id, &self.props.id)
215	            .set(scope_attr, scope_val)
216	            .set(part_attr, part_val);
217	
218	        let role_str = match self.props.role {
219	            GroupRole::Group => "group",
220	            GroupRole::Region => "region",
221	            GroupRole::Presentation => "presentation",
222	        };
223	        attrs.set(HtmlAttr::Role, role_str);
224	
225	        if self.props.disabled {
226	            attrs
227	                .set(HtmlAttr::Aria(AriaAttr::Disabled), "true")
228	                .set_bool(HtmlAttr::Data("ars-disabled"), true);
229	        }
230	        if self.props.invalid {
231	            attrs
232	                .set(HtmlAttr::Aria(AriaAttr::Invalid), "true")
233	                .set_bool(HtmlAttr::Data("ars-invalid"), true);
234	        }
235	        if self.props.read_only {
236	            attrs
237	                .set(HtmlAttr::Aria(AriaAttr::ReadOnly), "true")
238	                .set_bool(HtmlAttr::Data("ars-readonly"), true);
239	        }
240	        if let Some(dir) = self.props.dir {
241	            attrs.set(HtmlAttr::Dir, dir.as_html_attr());
242	        }
243	
244	        attrs
245	    }
246	}
247	
248	impl ConnectApi for Api {
249	    type Part = Part;
250	
251	    fn part_attrs(&self, part: Part) -> AttrMap {
252	        match part {
253	            Part::Root => self.root_attrs(),
254	        }
255	    }
256	}
257	
258	#[cfg(test)]
259	mod tests {
260	    use ars_core::HasId;
261	    use insta::assert_snapshot;
262	
263	    use super::*;
264	
265	    fn snapshot_attrs(attrs: &AttrMap) -> String {
266	        format!("{attrs:#?}")
267	    }
268	
269	    fn default_props() -> Props {
270	        Props::default()
271	    }
272	
273	    fn region_props() -> Props {
274	        Props::new().role(GroupRole::Region)
275	    }
276	
277	    fn presentation_props() -> Props {
278	        Props::new().role(GroupRole::Presentation)
279	    }
