518	        // `role="presentation"` group still see the disabled state.
519	        let ctx_group = Api::new(Props::new().disabled(true)).group_context();
520	        let ctx_region =
521	            Api::new(Props::new().disabled(true).role(GroupRole::Region)).group_context();
522	        let ctx_presentation =
523	            Api::new(Props::new().disabled(true).role(GroupRole::Presentation)).group_context();
524	
